import React, { useEffect, useState } from "react";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWButton from "../../../../component-widget/FAWButton";
import FAWItemOptionsEditor from "./shared/FAWItemOptionsEditor";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWFlagSettings from "./shared/FAWFlagSettings";
import FAWAddPrefill from "./shared/FAWAddPrefill";
import FAWCloningOptions from "./shared/FAWCloningOptions";

export default function QueMatrixQuestionEditor({ 
  data, 
  onSave, 
  onClose, 
  saveRef, 
  isDefaultLanguage = true,
  availableDroplists = [],
  availableFormFields = [],
  availableRefDomains = [],
  domains = []
}) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      matrixRows: [], // Questions/statements to be rated
      matrixColumns: [], // Rating scale options (e.g., Strongly Agree, Agree, etc.)
      matrixType: "Rating", // Rating, YesNo, Custom
      allowMultipleSelection: false,
      flagSettings: {},
      prefillSettings: {},
      cloningOptions: {},
    }
  );
  // Add isSubForm state
  const [isSubForm, setIsSubForm] = useState(data?.isSubForm || false);

  const [editingRow, setEditingRow] = useState(null);
  const [newRow, setNewRow] = useState({
    text: "",
    value: "",
    required: false,
  });

  const [editingColumn, setEditingColumn] = useState(null);
  const [newColumn, setNewColumn] = useState({
    text: "",
    value: "",
    weight: 1,
  });

  useEffect(() => { 
    if (data) setItem(prev => ({ ...prev, ...data })); 
  }, [data]);

  const handleChange = (field, value) => setItem(prev => ({ ...prev, [field]: value }));
  const handleSave = () => { 
    onSave?.(item); 
  };

  // Matrix Type Options
  const getMatrixTypeOptions = () => [
    { label: "Rating Scale", value: "Rating" },
    { label: "Yes/No Questions", value: "YesNo" },
    { label: "Custom Options", value: "Custom" }
  ];

  // Predefined rating scales
  const getPredefinedColumns = (type) => {
    switch (type) {
      case "Rating":
        return [
          { text: "Strongly Disagree", value: "1", weight: 1 },
          { text: "Disagree", value: "2", weight: 2 },
          { text: "Neutral", value: "3", weight: 3 },
          { text: "Agree", value: "4", weight: 4 },
          { text: "Strongly Agree", value: "5", weight: 5 }
        ];
      case "YesNo":
        return [
          { text: "Yes", value: "Yes", weight: 1 },
          { text: "No", value: "No", weight: 0 }
        ];
      default:
        return [];
    }
  };

  // Handle matrix type change
  const handleMatrixTypeChange = (newType) => {
    const predefinedColumns = getPredefinedColumns(newType);
    setItem(prev => ({
      ...prev,
      matrixType: newType,
      matrixColumns: predefinedColumns.length > 0 ? predefinedColumns : prev.matrixColumns
    }));
  };

  // Row Management
  const handleAddRow = () => {
    if (!newRow.text) {
      alert("Row text is required");
      return;
    }

    const row = {
      id: Date.now(),
      ...newRow,
      value: newRow.value || newRow.text.replace(/\s+/g, '_').toLowerCase()
    };

    setItem(prev => ({
      ...prev,
      matrixRows: [...prev.matrixRows, row]
    }));

    setNewRow({ text: "", value: "", required: false });
  };

  const handleEditRow = (row) => {
    setEditingRow(row);
    setNewRow({
      text: row.text,
      value: row.value,
      required: row.required,
    });
  };

  const handleUpdateRow = () => {
    if (!editingRow) return;

    if (!newRow.text) {
      alert("Row text is required");
      return;
    }

    const updatedRows = item.matrixRows.map(row => 
      row.id === editingRow.id 
        ? { ...row, ...newRow }
        : row
    );

    setItem(prev => ({
      ...prev,
      matrixRows: updatedRows
    }));

    setEditingRow(null);
    setNewRow({ text: "", value: "", required: false });
  };

  const handleDeleteRow = (rowId) => {
    if (confirm("Are you sure you want to delete this row?")) {
      setItem(prev => ({
        ...prev,
        matrixRows: prev.matrixRows.filter(row => row.id !== rowId)
      }));
    }
  };

  // Column Management
  const handleAddColumn = () => {
    if (!newColumn.text) {
      alert("Column text is required");
      return;
    }

    const column = {
      id: Date.now(),
      ...newColumn,
      value: newColumn.value || newColumn.text.replace(/\s+/g, '_').toLowerCase()
    };

    setItem(prev => ({
      ...prev,
      matrixColumns: [...prev.matrixColumns, column]
    }));

    setNewColumn({ text: "", value: "", weight: 1 });
  };

  const handleEditColumn = (column) => {
    setEditingColumn(column);
    setNewColumn({
      text: column.text,
      value: column.value,
      weight: column.weight,
    });
  };

  const handleUpdateColumn = () => {
    if (!editingColumn) return;

    if (!newColumn.text) {
      alert("Column text is required");
      return;
    }

    const updatedColumns = item.matrixColumns.map(col => 
      col.id === editingColumn.id 
        ? { ...col, ...newColumn }
        : col
    );

    setItem(prev => ({
      ...prev,
      matrixColumns: updatedColumns
    }));

    setEditingColumn(null);
    setNewColumn({ text: "", value: "", weight: 1 });
  };

  const handleDeleteColumn = (columnId) => {
    if (confirm("Are you sure you want to delete this column?")) {
      setItem(prev => ({
        ...prev,
        matrixColumns: prev.matrixColumns.filter(col => col.id !== columnId)
      }));
    }
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} questionType="MatrixQuestionItemType" />
      
      <EditorSection title="Matrix Configuration">
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
          <FAWDropdown
            label="Matrix Type"
            value={item.matrixType}
            options={getMatrixTypeOptions()}
            onChange={(opt) => handleMatrixTypeChange(opt.value)}
            fullWidth
          />
          <div style={{ display: "flex", alignItems: "center", marginTop: 24 }}>
            <FAWCheckbox 
              label="Allow Multiple Selections per Row" 
              checked={item.allowMultipleSelection} 
              onChange={(e) => handleChange("allowMultipleSelection", e.target.checked)} 
            />
          </div>
        </div>
      </EditorSection>

      <EditorSection title="Matrix Rows (Questions/Statements)">
        <div style={{ marginBottom: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr auto", gap: 16, marginBottom: 16 }}>
            <FAWInput 
              label="Row Text" 
              value={newRow.text} 
              onChange={(e) => setNewRow(prev => ({ ...prev, text: e.target.value }))} 
              fullWidth 
            />
            <FAWInput 
              label="Value (optional)" 
              value={newRow.value} 
              onChange={(e) => setNewRow(prev => ({ ...prev, value: e.target.value }))} 
              fullWidth 
            />
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 24 }}>
              <FAWCheckbox 
                label="Required" 
                checked={newRow.required} 
                onChange={(e) => setNewRow(prev => ({ ...prev, required: e.target.checked }))} 
              />
              {editingRow ? (
                <>
                  <FAWButton variant="contained" onClick={handleUpdateRow}>Update</FAWButton>
                  <FAWButton variant="outlined" onClick={() => {
                    setEditingRow(null);
                    setNewRow({ text: "", value: "", required: false });
                  }}>Cancel</FAWButton>
                </>
              ) : (
                <FAWButton variant="contained" onClick={handleAddRow}>Add Row</FAWButton>
              )}
            </div>
          </div>
        </div>

        {item.matrixRows.length > 0 && (
          <div style={{ border: "1px solid #ddd", borderRadius: 4, overflow: "hidden" }}>
            <div style={{ backgroundColor: "#f5f5f5", padding: "8px 16px", fontWeight: "bold", display: "grid", gridTemplateColumns: "2fr 1fr auto auto auto", gap: 16 }}>
              <span>Text</span>
              <span>Value</span>
              <span>Required</span>
              <span>Actions</span>
            </div>
            {item.matrixRows.map((row, index) => (
              <div key={row.id} style={{ 
                padding: "8px 16px", 
                borderTop: index > 0 ? "1px solid #eee" : "none",
                display: "grid", 
                gridTemplateColumns: "2fr 1fr auto auto auto", 
                gap: 16,
                alignItems: "center"
              }}>
                <span>{row.text}</span>
                <span>{row.value}</span>
                <span>{row.required ? "Yes" : "No"}</span>
                <FAWButton size="small" variant="outlined" onClick={() => handleEditRow(row)}>Edit</FAWButton>
                <FAWButton size="small" variant="outlined" color="error" onClick={() => handleDeleteRow(row.id)}>Delete</FAWButton>
              </div>
            ))}
          </div>
        )}
      </EditorSection>

      <EditorSection title="Matrix Columns (Response Options)">
        {item.matrixType === "Custom" && (
          <div style={{ marginBottom: 16 }}>
            <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr 1fr auto", gap: 16, marginBottom: 16 }}>
              <FAWInput 
                label="Column Text" 
                value={newColumn.text} 
                onChange={(e) => setNewColumn(prev => ({ ...prev, text: e.target.value }))} 
                fullWidth 
              />
              <FAWInput 
                label="Value (optional)" 
                value={newColumn.value} 
                onChange={(e) => setNewColumn(prev => ({ ...prev, value: e.target.value }))} 
                fullWidth 
              />
              <FAWInput 
                label="Weight/Score" 
                value={newColumn.weight} 
                onChange={(e) => setNewColumn(prev => ({ ...prev, weight: parseInt(e.target.value) || 1 }))} 
                type="number"
                fullWidth 
              />
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 24 }}>
                {editingColumn ? (
                  <>
                    <FAWButton variant="contained" onClick={handleUpdateColumn}>Update</FAWButton>
                    <FAWButton variant="outlined" onClick={() => {
                      setEditingColumn(null);
                      setNewColumn({ text: "", value: "", weight: 1 });
                    }}>Cancel</FAWButton>
                  </>
                ) : (
                  <FAWButton variant="contained" onClick={handleAddColumn}>Add Column</FAWButton>
                )}
              </div>
            </div>
          </div>
        )}

        {item.matrixColumns.length > 0 && (
          <div style={{ border: "1px solid #ddd", borderRadius: 4, overflow: "hidden" }}>
            <div style={{ backgroundColor: "#f5f5f5", padding: "8px 16px", fontWeight: "bold", display: "grid", gridTemplateColumns: "2fr 1fr 1fr auto auto", gap: 16 }}>
              <span>Text</span>
              <span>Value</span>
              <span>Weight</span>
              <span>Actions</span>
            </div>
            {item.matrixColumns.map((column, index) => (
              <div key={column.id || index} style={{ 
                padding: "8px 16px", 
                borderTop: index > 0 ? "1px solid #eee" : "none",
                display: "grid", 
                gridTemplateColumns: "2fr 1fr 1fr auto auto", 
                gap: 16,
                alignItems: "center"
              }}>
                <span>{column.text}</span>
                <span>{column.value}</span>
                <span>{column.weight}</span>
                {item.matrixType === "Custom" ? (
                  <>
                    <FAWButton size="small" variant="outlined" onClick={() => handleEditColumn(column)}>Edit</FAWButton>
                    <FAWButton size="small" variant="outlined" color="error" onClick={() => handleDeleteColumn(column.id)}>Delete</FAWButton>
                  </>
                ) : (
                  <span style={{ gridColumn: "span 2", color: "#666", fontStyle: "italic" }}>Predefined</span>
                )}
              </div>
            ))}
          </div>
        )}
      </EditorSection>

      <div style={{ display: 'none' }}>
        <FAWFlagSettings 
          data={item.flagSettings} 
          onChange={(data) => handleChange("flagSettings", data)}
          availableFlags={[]}
        />
      </div>
      
      {isDefaultLanguage && !isSubForm && availableFormFields.length > 0 && (
        <EditorSection title="Prefill Options">
          <FAWAddPrefill 
            data={item.prefillSettings} 
            onChange={(data) => handleChange("prefillSettings", data)}
            availablePrefillFields={availableFormFields}
          />
        </EditorSection>
      )}
      
      <FAWCloningOptions 
        data={item.cloningOptions} 
        onChange={(data) => handleChange("cloningOptions", data)}
      />
    </EditorShell>
  );
}
