import React, { useState, useEffect } from "react";
import FAWDropdown from "../../../../../component-widget/FAWDropdown";

export default function FAWAddPrefill({ 
  data = {}, 
  onChange,
  availablePrefillFields = [],
  prefillFieldFrom = "",
  isDeployed = false
}) {
  const [localData, setLocalData] = useState({
    prefillFieldFrom: prefillFieldFrom
  });

  useEffect(() => {
    setLocalData({
      prefillFieldFrom: data.prefillFieldFrom ?? ""
    });
  }, [data.prefillFieldFrom]);

  const handleChange = (field, value) => {
    const newData = { ...localData, [field]: value };
    setLocalData(newData);
    onChange?.(newData);
  };

  // Convert availablePrefillFields to dropdown options
  const dropdownOptions = availablePrefillFields.map(field => ({
    value: field.value || field.name || field,
    label: field.label || field.text || field.name || field
  }));

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <FAWDropdown
        label=""
        value={localData.prefillFieldFrom}
        onChange={(selectedOption, e) => {
          // FAWDropdown passes (selectedOption, event) as parameters
          // Use selectedOption.value instead of e.target.value
          const value = selectedOption?.value || selectedOption?.Value || "";
          handleChange("prefillFieldFrom", value);
        }}
        options={dropdownOptions}
        disabled={isDeployed}
        fullWidth
        placeholder="--Select--"
      />
      {dropdownOptions.length === 0 && (
        <div style={{ 
          fontSize: '12px', 
          color: '#666', 
          fontStyle: 'italic',
          marginTop: '4px'
        }}>
          No form fields available for prefill
        </div>
      )}
    </div>
  );
}
